UPDATE_BY_NAME,
UPDATE_TIME
FROM
T_FD_CREDIT_DEBIT_BILL_DETAIL


        and ID = #{id}


        and CNDN_ID = #{cndnId}


        and INVOICE_DETAIL_ID = #{invoiceDetailId}


        and PORT_CODE = #{portCode}


        and PORT_NAME = #{portName}


        and MEA = #{mea}


        and RATE_CODE = #{rateCode}


        and RATE_NAME = #{rateName}


        and OLD_RATE = #{oldRate}


        and NEW_RATE = #{newRate}


        and CARGO_TYPE_CODE = #{cargoTypeCode}


        and CARGO_CODE = #{cargoCode}


        and TAX_RATE = #{taxRate}


        and TAX_AMOUNT = #{taxAmount}


        and PAYMENT_METHOD_CODE = #{paymentMethodCode}


        and PAYMENT_METHOD_NAME = #{paymentMethodName}


        and BANK_ID = #{bankId}


        and AMOUNT = #{amount}

